  "inlineSchema": "// Esquema de base de datos para Sistema de Inventarios\n\ngenerator client {\n  provider        = \"prisma-client-js\"\n  previewFeatures = [\"driverAdapters\"]\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  // Only use directUrl for Prisma migrate - uses unpooled for full SQL support\n  directUrl = env(\"DATABASE_URL_UNPOOLED\")\n}\n\nenum Rol {\n  ADMIN\n  USUARIO\n}\n\nenum Permiso {\n  VER_ANALISIS\n  EXPORTAR_REPORTES\n  REGISTRAR_MOVIMIENTOS\n  REALIZAR_VENTAS\n  // Esta rama (C) solo usa REGISTRAR_MOVIMIENTOS y REALIZAR_VENTAS en su\n  // UI/logica, pero el enum debe incluir todos los valores que existen en\n  // la BD para que Prisma no falle al hidratar registros con permisos de\n  // ramas hermanas.\n  AGREGAR_STOCK\n  DESCONTAR_STOCK\n}\n\nmodel Usuario {\n  id                     Int          @id @default(autoincrement())\n  nombreUsuario          String       @unique\n  contrasena             String\n  nombre                 String\n  rol                    Rol          @default(USUARIO)\n  permisos               Permiso[]    @default([])\n  creadoEn               DateTime     @default(now())\n  auditorias             Auditoria[]\n  ventas                 Venta[]      @relation(\"VentaVendedor\")\n  cancelaciones          Venta[]      @relation(\"VentaCanceladaPor\")\n  cotizaciones           Cotizacion[] @relation(\"CotizacionVendedor\")\n  cotizacionesCanceladas Cotizacion[] @relation(\"CotizacionCanceladaPor\")\n}\n\nmodel Categoria {\n  id        Int        @id @default(autoincrement())\n  nombre    String     @unique\n  // Prefijo usado para los codigos de los productos de esta categoria\n  // (ej. \"BEB\", \"ALI\"). Se rellena en migracion para todas las categorias\n  // existentes y es obligatorio para nuevas.\n  prefijo   String     @unique\n  productos Producto[]\n}\n\nmodel Producto {\n  id              Int              @id @default(autoincrement())\n  nombre          String\n  descripcion     String?\n  codigo          String           @unique\n  precio          Float\n  cantidad        Int              @default(0)\n  stockMinimo     Int              @default(1)\n  // Categoria obligatoria. Los productos sin categoria previa se reasignan\n  // a la categoria \"Sin clasificar\" en la migracion.\n  categoriaId     Int\n  categoria       Categoria        @relation(fields: [categoriaId], references: [id])\n  movimientos     Movimiento[]\n  itemsVenta      ItemVenta[]\n  itemsCotizacion ItemCotizacion[]\n  creadoEn        DateTime         @default(now())\n}\n\nmodel Movimiento {\n  id         Int      @id @default(autoincrement())\n  productoId Int\n  producto   Producto @relation(fields: [productoId], references: [id])\n  tipo       String // \"entrada\" o \"salida\"\n  cantidad   Int\n  notas      String?\n  ventaId    Int?\n  venta      Venta?   @relation(fields: [ventaId], references: [id], onDelete: SetNull)\n  creadoEn   DateTime @default(now())\n\n  @@index([ventaId])\n}\n\nmodel Venta {\n  id                Int          @id @default(autoincrement())\n  vendedorId        Int?\n  vendedor          Usuario?     @relation(\"VentaVendedor\", fields: [vendedorId], references: [id], onDelete: SetNull)\n  total             Float\n  notas             String?\n  items             ItemVenta[]\n  movimientos       Movimiento[]\n  creadoEn          DateTime     @default(now())\n  canceladaEn       DateTime?\n  canceladaPorId    Int?\n  canceladaPor      Usuario?     @relation(\"VentaCanceladaPor\", fields: [canceladaPorId], references: [id], onDelete: SetNull)\n  motivoCancelacion String?\n  // Si esta venta nacio de convertir una cotizacion, la cotizacion la apunta.\n  cotizacionOrigen  Cotizacion?  @relation(\"CotizacionConvertida\")\n\n  @@index([creadoEn(sort: Desc)])\n  @@index([vendedorId])\n  @@index([canceladaEn])\n}\n\nmodel ItemVenta {\n  id             Int      @id @default(autoincrement())\n  ventaId        Int\n  venta          Venta    @relation(fields: [ventaId], references: [id], onDelete: Cascade)\n  productoId     Int\n  producto       Producto @relation(fields: [productoId], references: [id])\n  cantidad       Int\n  precioUnitario Float\n  subtotal       Float\n\n  @@index([ventaId])\n  @@index([productoId])\n}\n\nenum EstadoCotizacion {\n  PENDIENTE // activa: reserva stock mientras validaHasta > now\n  CONVERTIDA // convertida a Venta (ventaId apunta a la venta resultante)\n  CANCELADA // cancelada manualmente, libera stock\n}\n\nmodel Cotizacion {\n  id                Int              @id @default(autoincrement())\n  vendedorId        Int?\n  vendedor          Usuario?         @relation(\"CotizacionVendedor\", fields: [vendedorId], references: [id], onDelete: SetNull)\n  cliente           String?\n  total             Float\n  notas             String?\n  items             ItemCotizacion[]\n  estado            EstadoCotizacion @default(PENDIENTE)\n  validaHasta       DateTime\n  creadoEn          DateTime         @default(now())\n  // Cuando se convierte: estado = CONVERTIDA y ventaId apunta a la Venta creada.\n  ventaId           Int?             @unique\n  venta             Venta?           @relation(\"CotizacionConvertida\", fields: [ventaId], references: [id], onDelete: SetNull)\n  convertidaEn      DateTime?\n  // Cuando se cancela.\n  canceladaEn       DateTime?\n  canceladaPorId    Int?\n  canceladaPor      Usuario?         @relation(\"CotizacionCanceladaPor\", fields: [canceladaPorId], references: [id], onDelete: SetNull)\n  motivoCancelacion String?\n\n  @@index([estado])\n  @@index([validaHasta])\n  @@index([creadoEn(sort: Desc)])\n  @@index([vendedorId])\n}\n\nmodel ItemCotizacion {\n  id             Int        @id @default(autoincrement())\n  cotizacionId   Int\n  cotizacion     Cotizacion @relation(fields: [cotizacionId], references: [id], onDelete: Cascade)\n  productoId     Int\n  producto       Producto   @relation(fields: [productoId], references: [id])\n  cantidad       Int\n  precioUnitario Float\n  subtotal       Float\n\n  @@index([cotizacionId])\n  @@index([productoId])\n}\n\nmodel Auditoria {\n  id        Int      @id @default(autoincrement())\n  usuarioId Int?\n  usuario   Usuario? @relation(fields: [usuarioId], references: [id], onDelete: SetNull)\n  accion    String // CREAR | ACTUALIZAR | ELIMINAR | LOGIN | LOGIN_FALLIDO\n  entidad   String // Producto | Categoria | Movimiento | Usuario | Sesion\n  entidadId Int?\n  datos     Json? // { antes: {...}, despues: {...} } o detalles especificos del evento\n  ip        String?\n  creadoEn  DateTime @default(now())\n\n  @@index([creadoEn(sort: Desc)])\n  @@index([usuarioId])\n  @@index([entidad, entidadId])\n  @@index([accion])\n}\n",
